exports.responseTransformation = function(args) {
    try {

        var response = args.responseMap;
console.log("-----response --",JSON.stringify(response.event.walletDetails));

        var walletDetails = response.event.payerInfo.walletDetails;
//console.log("-----payerInfo--",JSON.stringify(payerInfo));

        var finalResponse = [];

        for (let i=0; i<walletDetails.length; i++) {
            var attr = walletDetails[i]["_attributes"];
            var spendGroupInAttributes = walletDetails[i].spendGroup;


            if (attr.walletType.toLowerCase() === "d") {
                continue;
            }
            var bucket = {
                "id" : "",
                "bucketType" : "",
                "remainedAmount" : {
                    "amount" : 0,
                    "units" : ""
                },
                "endDateTime" : ""
            };
            bucket.id = attr.walletId;
            bucket.bucketType = attr.walletShortDescription;
            bucket.remainedAmount.amount = parseInt(attr.balanceUnits);
            if (attr.walletType.toLowerCase() === "b") {
            bucket.remainedAmount.amount = parseInt(attr.balanceUnits)/1000000;
            }
            bucket.remainedAmount.units = attr.unitDescription;
            if (spendGroupInAttributes){
                bucket.spendGroup = spendGroupInAttributes;
            }

            bucket.endDateTime = attr.walletexpiryDate;

            finalResponse.push(bucket);
        }

        return finalResponse;
    } catch (error) {
        console.log("---- Error Description ----", error.message);
        return response;
    }  
};

