exports.getUsageBalanceDetailsScript = function (args) {
    try {
        var request = args;
        var productInventory = request.getProductInventoryDetails;
        var walletDetails = request.getBalanceFromDOCS.event.payerInfo.walletDetails;

        productInventory.forEach((prod) => {
            var extSystems = prod.productOffering.externalSystem;
            var docSystem = extSystems.find((sys) => sys.system === "DOCS");
            if (!docSystem) return;

            var productId = docSystem.id;


            var matchingWallets = walletDetails.filter(
                (wallet) => wallet?._attributes?.walletType === "D" && wallet._attributes.tariffId === productId
            );

            if (matchingWallets.length > 0) {
                (prod.productTerm || []).forEach((term) => {
                    if (term?.validFor) {
                        term.validFor.startDateTime = matchingWallets[0]._attributes.tariffStartDate;
                        term.validFor.endDateTime = matchingWallets[0]._attributes.walletexpiryDate;
                    }
                });


               if (!Array.isArray(prod.characteristic)) {
                    prod.characteristic = [];
                }


                matchingWallets.forEach((wallet) => {
                    var attrs = wallet._attributes;


                    prod.characteristic.push({
                        name: attrs.creditDescription,
                        initialValue: attrs.creditUnits,
                        currentValue: attrs.balanceUnits,
                        unitOfMeasure: attrs.unitDescription,
                        "@type": "Allowance"
                    });
                });

        }
        });
//console.log("------response-----",JSON.stringify(productInventory));
        return productInventory;
    } catch (err) {
        console.error("Error in getUsageBalanceDetailsScript:", err);
        return args;
    }
};

