exports.frameRequestForMaDaUpdate = function (args) {
  console.log("=== MA DA ARGS ===", JSON.stringify(args));
  var request = args.requestMap;
  var config = args.config;

  let orderItem = request.orderItem.find((ele) => ele.action.toLowerCase() === "modify" && ele.serviceSpecification.refferedType.toLowerCase() === "modifymadaamount");
  let serviceDetails = orderItem.service[0];
  let serviceCharacteristic = serviceDetails.serviceCharacteristic;
  var entityId = config.msisdnPrefix + serviceDetails.publicIdentifier;

  var endpoint = `/docs-api-service/financeManagement/v1/MVNO/0/Subscriber/${entityId}/Balance`;

  var transactionAmount = serviceCharacteristic.find((ele) => ele.name.toLowerCase() === "amount").value.toString();
  var decimals = transactionAmount.split(".");
  var chargeExponent = "0";
  if (decimals.length === 2) {
    chargeExponent = "-" + decimals[1].toString().length;
  }
  var walletId = null;
  var articleId = null;
  var transactionType = serviceCharacteristic.find((ele) => ele.name.toLowerCase() === "transactiontype").value;
  if (transactionType.toLowerCase() === "i") {
    transactionType = "credit";
    transactionAmount = "-" + transactionAmount;
  } else {
    transactionType = "debit";
  }

  var operationType = serviceCharacteristic.find((ele) => ele.name.toLowerCase() === "operationtype").value;
  if (operationType.toLowerCase() === "ma") {
    walletId = config.maDaBalance.maBalanceWalletId;
    articleId = config.maDaBalance.maBalanceArticleId;
  } else {
    walletId = serviceCharacteristic.find((ele) => ele.name.toLowerCase() === "id").value;
    articleId = config.maDaBalance.daBalanceArticleId;
  }

  var date = new Date();
  var referenceNumber = date.getFullYear() + ("0" + (date.getMonth() + 1)).slice(-2) + ("0" + date.getDate()).slice(-2) + ("0" + date.getHours()).slice(-2) + ("0" + date.getMinutes()).slice(-2) + ("0" + date.getSeconds()).slice(-2);
  var randomNo = Math.floor(Math.random() * 90) + 10;
  referenceNumber = referenceNumber + "" + randomNo;

  var finalPayload = {
    endpoint: endpoint,
    payload: {
      event: {
        entityType: {
          value: "E",
        },
        entityId: {
          value: entityId,
        },
        transactionType: {
          value: transactionType,
        },
        chargeExponent: {
          value: chargeExponent,
        },

        referenceNumber: {
          value: referenceNumber,
        },
        eventSource: {
          value: "DCLM",
        },
        forceDebit: {
          value: "1",
        },
        applyTax: {
          value: "0",
        },
        numberOfTransactions: {
          value: "1",
        },
        transactionInfo: {
          transaction: [
            {
              transactionAmount: transactionAmount,
              walletId: walletId,
              articleId: articleId,
              balanceOption: "0",
            }
          ]
        }
      }
    }
  };
  console.log("---- Request payload for Ma Da Balance ----", JSON.stringify(finalPayload));
  args.requestMap = finalPayload;
  return args;
};

