exports.minimalPayloadRegistration = function (args) {
 console.log("Inside the minimalPayload..... ", JSON.stringify(args));
  var dclmPayloadFormat = {
    "@type": "RegistrationRequest",
    status: "captured",
    interactionItem: [
      {
        item: {
          "@baseType": "PartyRole",
          "@type": "Customer",
          engagedParty: {
            "@baseType": "Party",
            "@type": "Individual",
          },
        },
      },
    ],
    channel: [
      {
        id: "3pp",
        name: "3pp",
        "@referredType": "Channel",
      },
    ],
  };

  var productOrderItem = {
    item: {
      "@type": "ProductOrder",
      orderItem: [],
    },
  };
//return dclmPayloadFormat;

  var physicalResource = args.payload;
  console.log("==== Payload is =====", args);
  var mainPlanId = args.config.mainPlanId;
  var topUpId = args.config.topUpId;
  try {
    var orderItems = [];
    var productOffering = physicalResource.productOffering;
    var resourceCharacteristics = physicalResource.resourceCharacteristic;
    var simNumber = resourceCharacteristics.find((ele) => ele.code.toLowerCase() === "sim").value;
    if (productOffering.length === 1) {
      if (productOffering.includes(mainPlanId)) {
        var orderItem = {
          action: "add",
          productOffering: {
            id: mainPlanId,
          },
          customFields: {
            autoReserveMSISDN: true,
          },
          orderItem: [
            {
              product: {
                characteristic: [
                  {
                    name: "SIMNumber",
                    value: simNumber,
                    "@type": "SIM",
                  },
                ],
              },
            },
          ],
        };
        orderItems.push(orderItem);
        productOrderItem.item.orderItem.push(...orderItems);
        dclmPayloadFormat.interactionItem.push(productOrderItem);
        return dclmPayloadFormat;
      } else {
        throw {code: 400, error: "mainPlanId does not match with productOffering"};
      }
    }
    if (productOffering.length > 1) {

        console.log("==== More than one offerings ====");
      var orderItemId = "OI1";
      if (productOffering.includes(mainPlanId)) {
        var orderItem = {
          id: orderItemId,
          action: "add",
          productOffering: {
            id: mainPlanId,
          },
          customFields: {
            autoReserveMSISDN: true,
          },
          orderItem: [
            {
              product: {
                characteristic: [
                  {
                    name: "SIMNumber",
                    value: simNumber,
                    "@type": "SIM",
                  },
                ],
              },
            },
          ],
