      } else {
        throw {code: 400, error: "mainPlanId does not match with productOffering"};
      }
      for (let i = 0; i < productOffering.length; i++) {
console.log("======= inside for loop ========:",i);
        if (productOffering[i] === topUpId) {
          var rechargeAmount = resourceCharacteristics.find((ele) => ele.code.toLowerCase() === "topup").value;
          var topUpOrderItem = {
            action: "add",
            actionSubType: "addVAS",
            productOffering: {
              id: topUpId,
            },
            product: {
              characteristic: [
                {
                  name: "Recharge Amount",
                  value: rechargeAmount,
                  "@type": "RechargeAmount",
                },
              ],
            },
            orderItemRelationship: [
              {
                type: "reliesOn",
                id: orderItemId,
              },
            ],
          };
          orderItems.push(topUpOrderItem);
          console.log("===== OrderIems 1 =====", orderItems);
        }
        if (productOffering[i] !== topUpId && productOffering[i] !== mainPlanId) {
          var bundleOrderItem = {
            action: "add",
            actionSubType: "addVAS",
            productOffering: {
              id: productOffering[i],
            },
            orderItemRelationship: [
              {
                type: "reliesOn",
                id: orderItemId,
              },
            ],
          };
          orderItems.push(bundleOrderItem);
        }
      }
      productOrderItem.item.orderItem.push(...orderItems);
      dclmPayloadFormat.interactionItem.push(productOrderItem);
      return dclmPayloadFormat;
    }
  } catch (error) {
    console.log("Error while parsing DOM Payload------>" + error);
    return error;
  }
};
